import java.io.*;import java.util.*;class Main{static class Cell{int r,c;Cell(int r,int c){this.r=r;this.c=c;}public boolean equals(Object o){if(!(o instanceof Cell))return false;Cell x=(Cell)o;return r==x.r&&c==x.c;}public int hashCode(){return r*131+c;}}static class Entry{int kind,val;HashMap<Cell,Integer> refs=new HashMap<>();Entry(int k,int v){kind=k;val=v;}Entry(HashMap<Cell,Integer> m){kind=1;refs=m;}}static class Excel{HashMap<Cell,Entry> cells=new HashMap<>();void set(int r,char c,int v){cells.put(new Cell(r,c-'A'),new Entry(0,v));}int get(int r,char c){Entry e=cells.get(new Cell(r,c-'A'));if(e==null)return 0;if(e.kind==0)return e.val;int sum=0;for(var x:e.refs.entrySet())sum+=get(x.getKey().r,(char)('A'+x.getKey().c))*x.getValue();return sum;}int sum(int r,char c,String[] nums){HashMap<Cell,Integer> refs=new HashMap<>();for(String s:nums){int p=s.indexOf(':');if(p<0){Cell x=parseCell(s);refs.put(x,refs.getOrDefault(x,0)+1);}else{Cell a=parseCell(s.substring(0,p)),b=parseCell(s.substring(p+1));for(int cc=a.c;cc<=b.c;cc++)for(int rr=a.r;rr<=b.r;rr++){Cell x=new Cell(rr,cc);refs.put(x,refs.getOrDefault(x,0)+1);}}}cells.put(new Cell(r,c-'A'),new Entry(refs));return get(r,c);}Cell parseCell(String s){return new Cell(Integer.parseInt(s.substring(1)),s.charAt(0)-'A');}}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int q=Integer.parseInt(d[idx++]);Excel ex=new Excel();ArrayList<String> ans=new ArrayList<>();for(int i=0;i<q;i++){String op=d[idx++];if(op.equals("C")){idx+=2;ans.add("null");}else if(op.equals("S")){ex.set(Integer.parseInt(d[idx++]),d[idx++].charAt(0),Integer.parseInt(d[idx++]));ans.add("null");}else if(op.equals("G")){ans.add(Integer.toString(ex.get(Integer.parseInt(d[idx++]),d[idx++].charAt(0))));}else{int r=Integer.parseInt(d[idx++]);char c=d[idx++].charAt(0);int k=Integer.parseInt(d[idx++]);String[] nums=new String[k];for(int j=0;j<k;j++)nums[j]=d[idx++];ans.add(Integer.toString(ex.sum(r,c,nums)));}}if(tc>0)out.append("\n\n");out.append("[").append(String.join(",",ans)).append("]");}System.out.print(out);}}
